SELECT "gene_name", var_expr FROM (SELECT "gene_name", VARIANCE("fpkm_uq_unstranded") AS var_expr FROM "TCGA"."TCGA_VERSIONED"."RNASEQ_HG38_GDC_R40" WHERE "project_short_name" = 'TCGA-BRCA' AND "sample_type_name" = 'Solid Tissue Normal' AND "case_barcode" IN (SELECT DISTINCT "case_barcode" FROM "TCGA"."TCGA_VERSIONED"."RNASEQ_HG38_GDC_R40" WHERE "project_short_name" = 'TCGA-BRCA' AND "sample_type_name" = 'Solid Tissue Normal') AND "gene_type" = 'protein_coding' GROUP BY "gene_name") ORDER BY var_expr DESC LIMIT 5